import { Schema, model, Document } from 'mongoose';

interface Group extends Document {
  name: string;
  description: string;
  adminId: Schema.Types.ObjectId;
  members: Schema.Types.ObjectId[];
  telegramChatId?: string;
  createdAt: Date;
}

const groupSchema = new Schema<Group>({
  name: { type: String, required: true },
  description: { type: String, required: true },
  adminId: { type: Schema.Types.ObjectId, required: true, ref: 'User' },
  members: [{ type: Schema.Types.ObjectId, ref: 'User' }],
  telegramChatId: { type: String },
  createdAt: { type: Date, default: Date.now }
});

export const GroupModel = model<Group>('Group', groupSchema);

import { Schema, model, Document } from 'mongoose';

interface Recurrence {
  type: 'daily' | 'weekly' | 'custom';
  daysOfWeek?: number[]; // [1, 3, 5] for Mon, Wed, Fri
  time: string; // "08:30"
}

interface Task extends Document {
  groupId: Schema.Types.ObjectId;
  title: string;
  description: string;
  assignees: Schema.Types.ObjectId[];
  rotationIndex: number;
  unavailableMembers?: Schema.Types.ObjectId[];
  recurrence: Recurrence;
  status: 'active' | 'paused';
}

const taskSchema = new Schema<Task>({
  groupId: { type: Schema.Types.ObjectId, required: true, ref: 'Group' },
  title: { type: String, required: true },
  description: { type: String, required: true },
  assignees: [{ type: Schema.Types.ObjectId, ref: 'User' }],
  rotationIndex: { type: Number, default: 0 },
  unavailableMembers: [{ type: Schema.Types.ObjectId, ref: 'User' }],
  recurrence: {
    type: { type: String, enum: ['daily', 'weekly', 'custom'], required: true },
    daysOfWeek: [Number],
    time: { type: String, required: true }
  },
  status: { type: String, enum: ['active', 'paused'], default: 'active' }
});

export const TaskModel = model<Task>('Task', taskSchema);
